commonErrors.correction:
*:focus-visible {
  outline: 2px solid #005fcc;
  outline-offset: 2px;
}
/* Ou alternative avec box-shadow */
button:focus {
  box-shadow: 0 0 0 3px rgba(0, 95, 204, 0.5);
}

commonErrors.example:
a:focus {
  outline: 2px solid #9aa0a6; /* couleur claire sur fond clair : contraste incertain */
}
